let[@axiom] tree_depth_node_lch = fun (l : (int tree)) -> fun (l1 : (int tree)) -> fun (l2 : (int tree)) -> fun (n1 : int) -> fun (n2 : int) -> (((depth l1 n1) && ((depth l2 n2) && ((lch l l1) && ((rch l l2) && (n1 >= n2))))) #==> (depth l (n1 + 1)))
let[@axiom] tree_depth_node_rch = fun (l : (int tree)) -> fun (l1 : (int tree)) -> fun (l2 : (int tree)) -> fun (n1 : int) -> fun (n2 : int) -> (((depth l1 n1) && ((depth l2 n2) && ((lch l l1) && ((rch l l2) && (n2 >= n1))))) #==> (depth l (n2 + 1)))
let[@axiom] tree_root_no_leaf = fun (l : (int tree)) (x : int) -> ((root l x) #==> (not (leaf l)))
let[@axiom] tree_leaf_or_root = fun (l : (int tree)) -> ((leaf l) || fun ((x [@ex]) : int) -> (root l x))
let[@axiom] tree_node_bst = fun (l : (int tree)) (l1 : (int tree)) (l2 : (int tree)) (x : int) -> (((bst l1) && ((bst l2) && ((lch l l1) && ((rch l l2) && ((root l x) && (((not (leaf l1)) #==> (upper_bound l1 x)) && ((not (leaf l2)) #==> (lower_bound l2 x)))))))) #==> (bst l))
let[@axiom] tree_lower_bound_base = fun (l : (int tree)) (l1 : (int tree)) (x : int) (y : int) -> (((bst l) && ((root l x) && ((lch l l1) && ((leaf l1) && (y < x))))) #==> (lower_bound l y))
let[@axiom] tree_lower_bound_other = fun (l : (int tree)) (l1 : (int tree)) (x : int) (y : int) -> (((bst l) && ((root l x) && ((lch l l1) && ((not (leaf l1)) && ((lower_bound l1 y) && (y < x)))))) #==> (lower_bound l y))
let[@axiom] tree_upper_bound_base = fun (l : (int tree)) (l1 : (int tree)) (x : int) (y : int) -> (((bst l) && ((root l x) && ((rch l l1) && ((leaf l1) && (y > x))))) #==> (upper_bound l y))
let[@axiom] tree_upper_bound_other = fun (l : (int tree)) (l1 : (int tree)) (x : int) (y : int) -> (((bst l) && ((root l x) && ((rch l l1) && ((not (leaf l1)) && ((upper_bound l1 y) && (y > x)))))) #==> (upper_bound l y))